import { Component, signal, HostListener } from '@angular/core';
import { CommonModule } from '@angular/common';
import { Router, RouterModule } from '@angular/router';

export type UserRole = 'guest' | 'student' | 'teacher' | 'parent' | 'admin';

export type UserVm = {
  id: string;
  firstName: string;
  lastName: string;
  email: string;
  role: UserRole;
};

@Component({
  selector: 'app-navbar',
  standalone: true,
  imports: [CommonModule, RouterModule],
  templateUrl: './navbar.component.html',
  styleUrls: ['./navbar.component.scss']
})
export class NavbarComponent {
  isScrolled = signal(false);
  isMobileMenuOpen = signal(false);
  isLoggedIn = signal(false);
  currentUser = signal<UserVm | null>(null);

  userInitials = () => {
    const user = this.currentUser();
    if (!user) return '';
    return `${user.firstName.charAt(0)}${user.lastName.charAt(0)}`.toUpperCase();
  };

  userRole = () => this.currentUser()?.role ?? 'guest';

  @HostListener('window:scroll', [])
  onWindowScroll() {
    this.isScrolled.set(window.scrollY > 50);
  }

  toggleMobileMenu() {
    this.isMobileMenuOpen.update(v => !v);
  }

  closeMobileMenu() {
    this.isMobileMenuOpen.set(false);
  }

  logout() {
    this.currentUser.set(null);
    this.isLoggedIn.set(false);
    this.router.navigate(['/']);
    this.closeMobileMenu();
  }

  constructor(private router: Router) {}
}
<nav class="fixed top-0 left-0 right-0 z-50 transition-all duration-300"
     [class]="isScrolled ? 'navbar-solid' : 'navbar-transparent'">
  <div class="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
    <div class="flex items-center justify-between h-16">
      <!-- Logo -->
      <div class="flex items-center">
        <a routerLink="/" class="flex items-center space-x-2 text-xl font-bold gradient-text">
          <svg class="w-8 h-8" fill="currentColor" viewBox="0 0 20 20">
            <path d="M9 4.804A7.968 7.968 0 005.5 4c-1.255 0-2.443.29-3.5.804v10A7.969 7.969 0 015.5 14c1.669 0 3.218.51 4.5 1.385A7.962 7.962 0 0114.5 14c1.255 0 2.443.29 3.5.804v-10A7.968 7.968 0 0014.5 4c-1.255 0-2.443.29-3.5.804V12a1 1 0 11-2 0V4.804z"/>
          </svg>
          <span>EduPlatform</span>
        </a>
      </div>

      <!-- Desktop Navigation -->
      <div class="hidden md:flex items-center space-x-8">
        <a routerLink="/courses" class="text-gray-700 hover:text-primary-600 transition-colors font-medium">
          Courses
        </a>
        <a routerLink="/live-sessions" class="text-gray-700 hover:text-primary-600 transition-colors font-medium">
          Live Sessions
        </a>
        <a routerLink="/exams" class="text-gray-700 hover:text-primary-600 transition-colors font-medium">
          Exams
        </a>
      </div>

      <!-- Desktop Auth Buttons -->
      <div class="hidden md:flex items-center space-x-4">
        <ng-container *ngIf="isLoggedIn$ | async; else loggedOut">
          <!-- User Menu -->
          <div class="relative group">
            <button class="flex items-center space-x-2 p-2 rounded-full hover:bg-gray-100 transition-colors">
              <div class="w-8 h-8 bg-gradient-to-r from-primary-600 to-pink-500 rounded-full flex items-center justify-center text-white font-semibold text-sm">
                {{ userInitials }}
              </div>
              <svg class="w-4 h-4 text-gray-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M19 9l-7 7-7-7"/>
              </svg>
            </button>

            <div class="absolute right-0 mt-2 w-48 bg-white rounded-lg shadow-lg py-2 opacity-0 invisible group-hover:opacity-100 group-hover:visible transition-all duration-200">
              <a routerLink="/dashboard" class="block px-4 py-2 text-gray-700 hover:bg-gray-100 transition-colors">
                Dashboard
              </a>
              <button (click)="logout()" class="w-full text-left px-4 py-2 text-gray-700 hover:bg-gray-100 transition-colors">
                Logout
              </button>
            </div>
          </div>
        </ng-container>

        <ng-template #loggedOut>
          <a routerLink="/login" class="text-gray-700 hover:text-primary-600 transition-colors font-medium">
            Sign In
          </a>
          <a routerLink="/register" class="btn-gradient">
            Get Started
          </a>
        </ng-template>
      </div>

      <!-- Mobile Menu Button -->
      <div class="md:hidden">
        <button (click)="toggleMobileMenu()" class="p-2 rounded-md text-gray-700 hover:text-primary-600 hover:bg-gray-100 transition-colors">
          <svg *ngIf="!isMobileMenuOpen" class="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M4 6h16M4 12h16M4 18h16"/>
          </svg>
          <svg *ngIf="isMobileMenuOpen" class="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M6 18L18 6M6 6l12 12"/>
          </svg>
        </button>
      </div>
    </div>

    <!-- Mobile Menu -->
    <div *ngIf="isMobileMenuOpen" class="md:hidden animate-slide-down">
      <div class="px-2 pt-2 pb-3 space-y-1 bg-white rounded-lg shadow-lg mt-2">
        <a routerLink="/courses" (click)="closeMobileMenu()" class="block px-3 py-2 text-gray-700 hover:text-primary-600 hover:bg-gray-50 rounded-md transition-colors">
          Courses
        </a>
        <a routerLink="/live-sessions" (click)="closeMobileMenu()" class="block px-3 py-2 text-gray-700 hover:text-primary-600 hover:bg-gray-50 rounded-md transition-colors">
          Live Sessions
        </a>
        <a routerLink="/exams" (click)="closeMobileMenu()" class="block px-3 py-2 text-gray-700 hover:text-primary-600 hover:bg-gray-50 rounded-md transition-colors">
          Exams
        </a>

        <div class="border-t border-gray-200 pt-2 mt-2">
          <ng-container *ngIf="isLoggedIn$ | async; else loggedOutMobile">
            <a routerLink="/dashboard" (click)="closeMobileMenu()" class="block px-3 py-2 text-gray-700 hover:text-primary-600 hover:bg-gray-50 rounded-md transition-colors">
              Dashboard
            </a>
            <button (click)="logout()" class="w-full text-left px-3 py-2 text-gray-700 hover:text-primary-600 hover:bg-gray-50 rounded-md transition-colors">
              Logout
            </button>
          </ng-container>

          <ng-template #loggedOutMobile>
            <a routerLink="/login" (click)="closeMobileMenu()" class="block px-3 py-2 text-gray-700 hover:text-primary-600 hover:bg-gray-50 rounded-md transition-colors">
              Sign In
            </a>
            <a routerLink="/register" (click)="closeMobileMenu()" class="block px-3 py-2 text-primary-600 hover:bg-gray-50 rounded-md transition-colors font-medium">
              Get Started
            </a>
          </ng-template>
        </div>
      </div>
    </div>
  </div>
</nav>
